using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.Metadata.Builders;
using Microsoft.EntityFrameworkCore.Metadata.Conventions;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed discriminator from "Discriminator" to "$type".
            // Keep the old name so existing 500K documents remain readable,
            // and direct SQL queries (WHERE c.Discriminator = ...) keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "Product|123" to just "123".
            // Preserve the old format for compatibility with existing documents.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id");
        });

        // HasIndex is no longer valid for the Cosmos provider in EF Core 9
        // (it was a no-op in EF Core 8 but now throws).
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Preserve EF Core 8 id format: "EntityType|KeyValue"
        configurationBuilder.Conventions.Add(_ =>
            new IdFormatConvention());
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } = string.Empty; }

/// <summary>
/// Convention that restores the EF Core 8 "EntityType|Key" id value generation
/// so new writes remain compatible with the 500K existing documents.
/// </summary>
class IdFormatConvention : IModelFinalizingConvention
{
    public void ProcessModelFinalizing(
        IConventionModelBuilder modelBuilder,
        IConventionContext<IConventionModelBuilder> context)
    {
        foreach (var entityType in modelBuilder.Metadata.GetEntityTypes())
        {
            entityType.SetIdValueGeneratorFactory(
                (property, type) => new LegacyIdValueGenerator());
        }
    }
}

class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var entityType = entry.Metadata.ShortName();
        var pk = entry.Property(entry.Metadata.FindPrimaryKey()!
            .Properties[0].Name).CurrentValue;
        return $"{entityType}|{pk}";
    }
}

